<?php include __DIR__ . '/../../includes/header.php'; require_permission('roles.ver');
$id=$_GET['id']??null; $role=['nombre_rol'=>'','descripcion'=>'']; if($id){$st=$pdo->prepare("SELECT * FROM roles WHERE id_rol=?");$st->execute([$id]);$role=$st->fetch();}
$perms=$pdo->query("SELECT * FROM permisos ORDER BY modulo,codigo")->fetchAll(); $current=[]; if($id){$st=$pdo->prepare("SELECT id_permiso FROM rol_permiso WHERE id_rol=?");$st->execute([$id]);$current=array_column($st->fetchAll(),'id_permiso');}
if($_SERVER['REQUEST_METHOD']==='POST'){ if($id){$pdo->prepare("UPDATE roles SET nombre_rol=?,descripcion=? WHERE id_rol=?")->execute([$_POST['nombre_rol'],$_POST['descripcion'],$id]);$pdo->prepare("DELETE FROM rol_permiso WHERE id_rol=?")->execute([$id]);} else {$pdo->prepare("INSERT INTO roles(nombre_rol,descripcion) VALUES(?,?)")->execute([$_POST['nombre_rol'],$_POST['descripcion']]);$id=$pdo->lastInsertId();}
foreach($_POST['permisos']??[] as $pid){$pdo->prepare("INSERT INTO rol_permiso(id_rol,id_permiso) VALUES(?,?)")->execute([$id,$pid]);} log_event('GUARDAR_ROL',$_POST['nombre_rol']); flash('success','Rol guardado.'); redirect('index.php');} ?>
<h1><?= $id?'Editar':'Nuevo' ?> rol</h1><div class="card"><form method="POST"><label>Nombre</label><input name="nombre_rol" value="<?= e($role['nombre_rol']) ?>" required><label>Descripción</label><textarea name="descripcion"><?= e($role['descripcion']) ?></textarea><h3>Permisos</h3><div class="two-col">
<?php foreach($perms as $p): ?><label><input style="width:auto" type="checkbox" name="permisos[]" value="<?= $p['id_permiso'] ?>" <?= in_array($p['id_permiso'],$current)?'checked':'' ?>> <?= e($p['modulo'].' - '.$p['descripcion']) ?></label><?php endforeach; ?></div><br><button>Guardar</button> <a class="btn btn-secondary" href="index.php">Volver</a></form></div><?php include __DIR__ . '/../../includes/footer.php'; ?>
